public sealed class ApproveProposalPayload : ITransactionPayload, ISmartContractInput
{
    public const int Size = 8;

    public ushort InputType => 7;
    public ushort InputSize => Size;
    public int SerializedSize => Size;

    public ulong ProposalId { get; init; }

    public byte[] GetPayloadBytes() => ToBytes();

    public byte[] ToBytes()
    {
        var bytes = new byte[Size];
        BinaryPrimitives.WriteUInt64LittleEndian(bytes.AsSpan(0), ProposalId);
        return bytes;
    }
}

/// <summary>Output.</summary>
public readonly struct ApproveProposalOutput : ISmartContractOutput<ApproveProposalOutput>
{
    public byte Status { get; init; }
    public bool Executed { get; init; }

    public static ApproveProposalOutput FromBytes(ReadOnlySpan<byte> data)
    {
        return new ApproveProposalOutput
        {
            Status = data.Slice(0, 1)[0],
            Executed = (data.Slice(1, 1)[0] != 0)
        };
    }
}

